  info = result
  so = getUrl();
  pw = info.密码

  if (b) {
    url = so + 'login,'
    body = `loginName=${info.邮箱}&password=${pw}&platform=`
  }  
   post = JSON.stringify({
    "body": String(body),
    "method": "POST"
  })
  url += post
  result = java.ajax(url)
  //java.log(result)
