exploreUrl:
@js:
sort=[];
push=(title,url,type1,type2)=>sort.push({
		title: title,
		url: url,
		style: {
				layout_flexGrow: type1,
				layout_flexBasisPercent: type2
			}
	});
D=org.jsoup.Jsoup.parse(java.ajax("https://www.manwamh.com/category"))
push("全部🔖分类",``,1,1)	
D.select("#area a").forEach(n=>{
	li=n.select("a")
	push(li.text(),`${li.attr("href")}/page/{{page}}`,1,0.39)
	})		
D.select("#theme a").forEach(t=>{
		push(t.text(),`${t.attr("href")}/page/{{page}}`,1,0.25)	
		});
D.select("#state a").forEach(n=>{
	li=n.select("a")
	push(li.text(),`${li.attr("href")}/page/{{page}}`,1,0.39)
});
//java.log(JSON.stringify(sort))
JSON.stringify(sort)

